qry:select.qry:xquery:
					for $r in sql('
maxsize 1001
SELECT 
LEG.oi_personal_emp as id
FROM 
PER01_PERSONAL as PER,
PER02_PERSONAL_EMP as LEG
JOIN
PER.oi_personal inner LEG.oi_personal
WHERE
LEG.oi_empresa={#SOURCE:@empresa}
{%?(#SOURCE:@search1!='') {% AND ( contain(ucase(LEG.e_numero_legajo), {upper-case(#SOURCE:@search1)}) or contain(ucase(PER.d_ape_y_nom), {upper-case(#SOURCE:@search1)}) %} {% %} %} 
{%?(#SOURCE:@search2!='') {% OR contain(ucase(LEG.e_numero_legajo), {upper-case(#SOURCE:@search2)}) or contain(ucase(PER.d_ape_y_nom), {upper-case(#SOURCE:@search2)}) %} {% %} %} 
{%?(#SOURCE:@search3!='') {% OR contain(ucase(LEG.e_numero_legajo), {upper-case(#SOURCE:@search3)}) or contain(ucase(PER.d_ape_y_nom), {upper-case(#SOURCE:@search3)}) %} {% %} %} 
{%?(#SOURCE:@search4!='') {% OR contain(ucase(LEG.e_numero_legajo), {upper-case(#SOURCE:@search4)}) or contain(ucase(PER.d_ape_y_nom), {upper-case(#SOURCE:@search4)}) %} {% %} %} 
{%?(#SOURCE:@search5!='') {% OR contain(ucase(LEG.e_numero_legajo), {upper-case(#SOURCE:@search5)}) or contain(ucase(PER.d_ape_y_nom), {upper-case(#SOURCE:@search5)}) %} {% %} %} 
{%?(#SOURCE:@search1!='') {% ) %} {% %} %}
{%?(#SOURCE:@where!='') {% AND {%=#SOURCE:@where %} %} {% %} %} 
')/ROWS/ROW

form:Form.form:Scripts:
		function PREV_exec_qry()
{
  var listLegajos,Where,t,subTxt,aux0,aux1,whereIN;
  Where="";
WhereIN="";  


  listLegajos=Ctrl('legajos').GetXValue();
  if (listLegajos!="")
  { 
  	listLegajos=Replace(listLegajos,"\r","");
    listLegajos=Replace(listLegajos,"\n",";");
    listLegajos=Replace(listLegajos,",",";");
    listLegajos=listLegajos.split(";");

    for (t=0; t<listLegajos.length; t++)
    { 
      if (listLegajos[t].indexOf("-")>=0)
      {
        subTxt=listLegajos[t].split("-");
        aux0=parseInt(subTxt[0],10);
        aux1=parseInt(subTxt[1],10);

        if ((!isNaN(aux0)) || (!isNaN(aux1)))
        {
            if (Where!="") Where+=" OR ";
          Where+="(";
            if (!isNaN(aux0)) Where+="LEG.e_numero_legajo >= "+aux0;
            if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
            if (!isNaN(aux1)) Where+="LEG.e_numero_legajo <= "+aux1;
          Where+=")";
        }
      } else
      {                           
        aux0=parseInt(listLegajos[t],10);
        if (!isNaN(aux0)) 
        {
          if (WhereIN!="") WhereIN+=",";
          WhereIN+=aux0;
        }
      }
    }
  }                                
  //Soporte para el IN
  Where = Where + (WhereIN ? (Where ? " OR " : "") + "LEG.e_numero_legajo in ("+WhereIN+")" : "");

  Ctrl("where").SetXValue(Where);
	return Where.length > 2000 ? "demasiados legajos, refinar la busqueda" : "";
}


function load_legajos() 
{ 
	internalLoad(function() { 

		Ctrl("chk").DelAllRow();
	  for (var n=0; n<arrLST.length; n++)
    	Ctrl("chk").AddRow().SetAttr("ID",arrLST[n]);                                       
    refreshList();

	}); 
}
